#include <bits/stdc++.h>
using namespace std;
struct Node{
    int val,id;
};
bool operator<(Node x,Node y){
    return x.val<y.val;
}
priority_queue<Node> q;
int n,l,r,a[200005],dp[200005];
int main(){
    scanf("%d%d%d",&n,&l,&r);
    for(int i=0;i<=n;i++)
        scanf("%d",&a[i]);
    for(int i=n;i>=0;i--){
        if(i+l<=n)
            q.push({dp[i+l],i+l});
        while(q.size() && q.top().id>i+r)
            q.pop();
        if(q.empty())
            dp[i]=a[i];
        else if(i+r>n)
            dp[i]=max(a[i]+q.top().val,a[i]);
        else
        	dp[i]=a[i]+q.top().val;
    }
    printf("%d",dp[0]);
    return 0;
}
